/* ============================================================
   buttons.css — สไตล์ปุ่มมาตรฐานใช้ร่วมกันทั้งระบบ
   ============================================================ */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 20px;
  border-radius: var(--radius-md);
  font-size: var(--fs-body);
  font-weight: 500;
  white-space: nowrap;
  transition: background var(--transition-fast), color var(--transition-fast),
              border-color var(--transition-fast), transform var(--transition-fast);
}

.btn i { font-size: 16px; }
.btn:active { transform: scale(0.98); }
.btn:disabled { opacity: 0.6; cursor: not-allowed; pointer-events: none; }

/* ---------- Variants ---------- */
.btn-primary {
  background: var(--color-primary);
  color: #fff;
}
.btn-primary:hover { background: var(--color-primary-hover); }

.btn-secondary {
  background: var(--color-bg);
  color: var(--color-text);
  border: 1px solid var(--color-border);
}
.btn-secondary:hover { background: var(--color-bg-canvas); border-color: var(--color-border-strong); }

.btn-ghost {
  background: transparent;
  color: var(--color-text-muted);
}
.btn-ghost:hover { background: var(--color-bg-canvas); color: var(--color-text); }

.btn-danger {
  background: var(--color-status-cancelled-bg);
  color: var(--color-status-cancelled);
}
.btn-danger:hover { background: var(--color-status-cancelled); color: #fff; }

.btn-outline-primary {
  background: transparent;
  color: var(--color-primary);
  border: 1px solid var(--color-primary);
}
.btn-outline-primary:hover { background: var(--color-primary-light); }

/* ---------- Sizes ---------- */
.btn-sm { padding: 6px 14px; font-size: var(--fs-small); }
.btn-lg { padding: 13px 28px; font-size: var(--fs-h3); }
.btn-block { width: 100%; }

/* ---------- Icon-only ---------- */
.btn-icon {
  width: 38px;
  height: 38px;
  padding: 0;
  border-radius: var(--radius-md);
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  color: var(--color-text-muted);
}
.btn-icon:hover { background: var(--color-bg-canvas); color: var(--color-primary); }

/* ---------- Loading state (ใช้ตอน submit ฟอร์ม) ---------- */
.btn.is-loading {
  position: relative;
  color: transparent !important;
  pointer-events: none;
}
.btn.is-loading::after {
  content: '';
  position: absolute;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  border: 2px solid rgba(255, 255, 255, 0.5);
  border-top-color: #fff;
  animation: spin 700ms linear infinite;
}
.btn-secondary.is-loading::after,
.btn-ghost.is-loading::after {
  border: 2px solid var(--color-border);
  border-top-color: var(--color-text-muted);
}
